import PassengerSidebar from "../../components/passenger/PassengerSidebar";
import PassengerTopbar from "../../components/passenger/PassengerTopbar";
import { useAuth } from "../../context/AuthContext";
import "../../styles/auth.css";
import "../../styles/global.css";

export default function PassengerDashboardPage() {
  const { user } = useAuth();

  const firstName = user?.firstName || user?.fullNames?.split(" ")?.[0] || "Passenger";
  const hour = new Date().getHours();
  const time = hour < 12 ? "morning" : hour < 17 ? "afternoon" : "evening";

  const totalTrips = user?.totalTrips ?? 47;
  const totalSpent = user?.totalSpent ?? 1240;
  const safetyScore = user?.safetyScore ?? 98;

  const trips = [
    {
      id: 1,
      from: "Menlyn Mall",
      to: "Hatfield Square",
      date: "Today, 08:14",
      duration: "12 min",
      amount: 48,
      icon: "🏢",
    },
    {
      id: 2,
      from: "Brooklyn",
      to: "Arcadia",
      date: "Yesterday, 17:32",
      duration: "8 min",
      amount: 31,
      icon: "🏠",
    },
    {
      id: 3,
      from: "Centurion",
      to: "Pretoria Airport",
      date: "4 Apr",
      duration: "22 min",
      amount: 95,
      icon: "✈️",
    },
  ];

  return (
    <div className="shell">
      <PassengerSidebar />

      <div className="main">
        <PassengerTopbar
          title={`Good ${time}, ${firstName}`}
          subtitle={new Date().toLocaleDateString("en-ZA", {
            weekday: "long",
            day: "numeric",
            month: "long",
            year: "numeric",
          })}
        />

        {/* Stats */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-label">Total Trips</div>
            <div className="stat-val text-p">{totalTrips}</div>
            <div className="stat-sub">All time</div>
          </div>

          <div className="stat-card">
            <div className="stat-label">Total Spent</div>
            <div className="stat-val">R{Number(totalSpent).toLocaleString("en-ZA")}</div>
            <div className="stat-sub">This month</div>
          </div>

          <div className="stat-card">
            <div className="stat-label">Safety Score</div>
            <div className="stat-val text-p">{safetyScore}%</div>
            <div className="stat-sub">Excellent</div>
          </div>
        </div>

        {/* Map */}
        <div className="map-area">
          <svg className="map-grid" width="100%" height="100%">
            <defs>
              <pattern id="dash-grid" width="30" height="30" patternUnits="userSpaceOnUse">
                <path d="M 30 0 L 0 0 0 30" fill="none" stroke="white" strokeWidth=".5" />
              </pattern>
            </defs>
            <rect width="100%" height="100%" fill="url(#dash-grid)" />
          </svg>
          <div className="map-pulse" />
          <div className="map-car">🚗</div>
          <div className="map-dot" style={{ top: "30%", left: "40%" }} />
          <div className="map-label">Your Location</div>
        </div>

        {/* Quick Actions */}
        <div className="section-title">Quick Actions</div>
        <div className="grid-4 mb-l">
          <a href="/passenger/book-ride" className="quick-btn">
            <span className="quick-icon">🚗</span>
            <span className="quick-label">Book Ride</span>
          </a>
          <a href="/passenger/trip-history" className="quick-btn">
            <span className="quick-icon">📋</span>
            <span className="quick-label">History</span>
          </a>
          <a href="/passenger/verification" className="quick-btn">
            <span className="quick-icon">🛡️</span>
            <span className="quick-label">Verify ID</span>
          </a>
          <a href="/passenger/active-trip" className="quick-btn">
            <span className="quick-icon">📍</span>
            <span className="quick-label">Live Trip</span>
          </a>
        </div>

        {/* Recent Trips */}
        <div className="section-title">Recent Trips</div>
        <div className="card">
          {trips.map((t) => (
            <div className="trip-row" key={t.id}>
              <div className="trip-icon">{t.icon}</div>
              <div className="trip-info">
                <div className="trip-route">
                  {t.from} → {t.to}
                </div>
                <div className="trip-date">
                  {t.date} · {t.duration}
                </div>
              </div>
              <div className="trip-amount text-p">R{t.amount}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
